   805→    // Get active jobs
   806→    const jobs = await pool.query(`
   807→      SELECT j.*, u.company_name as posted_by_company
   808→      FROM jobs j
   809→      LEFT JOIN users u ON j.user_id = u.id
   810→      WHERE j.status = 'active'
   811→      ORDER BY j.created_at DESC
   812→      LIMIT $1
   813→    `, [limit]);
