          passed: parseInt(assessmentCount.rows[0]?.passed) || 0
        }
      }
    });
  } catch (err) {
    console.error('Get dashboard stats error:', err);
    res.status(500).json({ error: 'Failed to get dashboard stats' });
  }
});

