      VALUES ($1, 'linkedin', $2, $3, $4)
      ON CONFLICT (provider, provider_user_id) DO UPDATE SET
        access_token = $3, profile_data = $4, updated_at = NOW()
    `, [user.id, linkedinUser.sub, tokens.access_token, JSON.stringify(linkedinUser)]);

