  try {
    const connections = await pool.query(
      'SELECT provider, created_at FROM oauth_connections WHERE user_id = $1',
      [req.user.id]
    );

    res.json({
      success: true,
      connections: connections.rows,
      has_password: !!req.user.password_hash
    });
